div.script:
/* eslint-disable */
(function () {
    'use strict';

    var langSel    = document.getElementById('speaking-lang');
    var topicEl    = document.getElementById('speaking-topic');
    var topicBtn   = document.getElementById('speaking-topic-btn');
    var recordBtn  = document.getElementById('speaking-record-btn');
    var stopBtn    = document.getElementById('speaking-stop-btn');
    var statusEl   = document.getElementById('speaking-status');
    var transEl    = document.getElementById('speaking-transcript');
    var analyzeBtn = document.getElementById('speaking-analyze-btn');

    var fbPanel    = document.getElementById('speaking-feedback');
    var fbImpBlock = document.getElementById('speaking-improved-block');
    var fbImproved = document.getElementById('speaking-improved');
    var fbCorrBlk  = document.getElementById('speaking-corrections-block');
    var fbCorrUl   = document.getElementById('speaking-corrections');
    var fbSynBlk   = document.getElementById('speaking-synonyms-block');
    var fbSynUl    = document.getElementById('speaking-synonyms');
    var fbEmpty    = document.getElementById('speaking-feedback-empty');

    if (!recordBtn) { return; }

    var mediaRecorder = null;
    var chunks = [];
    var currentSessionId = null;

    function setStatus(msg, kind) {
        if (!statusEl) return;
        statusEl.textContent = msg;
        statusEl.className = 'small ' + (
            kind === 'error' ? 'text-danger' :
            kind === 'busy'  ? 'text-warning' :
            kind === 'ok'    ? 'text-success' : 'text-white-50'
        );
    }

    function escapeHtml(s) {
        return String(s == null ? '' : s)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function pickMimeType() {
        var candidates = [
            'audio/webm;codecs=opus',
            'audio/webm',
            'audio/ogg;codecs=opus',
            'audio/ogg',
        ];
        for (var i = 0; i < candidates.length; i++) {
            if (window.MediaRecorder &&
                MediaRecorder.isTypeSupported(candidates[i])) {
                return candidates[i];
            }
        }
        return '';
    }

    // ── Generate Topic ─────────────────────────────────
    if (topicBtn) {
        topicBtn.addEventListener('click', function () {
            var lang = langSel ? langSel.value : 'en';
            topicBtn.disabled = true;
            setStatus('Generating topic…', 'busy');
            fetch('/my/speaking/topic', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                credentials: 'include',
                body: JSON.stringify({jsonrpc: '2.0', method: 'call',
                                      params: {language: lang}}),
            })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                topicBtn.disabled = false;
                var result = (data && data.result) || {};
                if (result.status === 'ok' && result.topic) {
                    topicEl.value = result.topic;
                    setStatus('Topic ready. Press Record.', 'ok');
                } else {
                    setStatus('Could not generate a topic — write your own.', 'error');
                }
            })
            .catch(function (err) {
                topicBtn.disabled = false;
                setStatus('Topic generation failed: ' + err, 'error');
            });
        });
    }

    // ── Record ─────────────────────────────────────────
    recordBtn.addEventListener('click', function () {
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
            setStatus('Browser does not support microphone capture.', 'error');
            return;
        }
        navigator.mediaDevices.getUserMedia({audio: true, video: false})
            .then(function (stream) {
                chunks = [];
                var mt = pickMimeType();
                var opts = mt ? {mimeType: mt} : undefined;
                try {
                    mediaRecorder = new MediaRecorder(stream, opts);
                } catch (e) {
                    mediaRecorder = new MediaRecorder(stream);
                }
                mediaRecorder.ondataavailable = function (ev) {
                    if (ev.data && ev.data.size > 0) {
                        chunks.push(ev.data);
                    }
                };
                mediaRecorder.onstop = function () {
                    stream.getTracks().forEach(function (t) { t.stop(); });
                    sendRecording(chunks, mediaRecorder.mimeType || 'audio/webm');
                };
                mediaRecorder.start();
                recordBtn.disabled = true;
                stopBtn.disabled = false;
                setStatus('🔴 Recording — speak now. Press Stop when done.', 'busy');
            })
            .catch(function (err) {
                setStatus('Microphone permission denied: ' + err.name, 'error');
            });
    });

    stopBtn.addEventListener('click', function () {
        if (mediaRecorder && mediaRecorder.state !== 'inactive') {
            mediaRecorder.stop();
            stopBtn.disabled = true;
            setStatus('Transcribing… (this may take 10-30 s)', 'busy');
        }
    });

    function sendRecording(chunks, mimeType) {
        if (!chunks.length) {
            setStatus('No audio captured.', 'error');
            recordBtn.disabled = false;
            return;
        }
        var blob = new Blob(chunks, {type: mimeType});
        var fd = new FormData();
        fd.append('audio', blob, 'speech.webm');
        fd.append('language', langSel ? langSel.value : 'en');
        fd.append('topic', (topicEl && topicEl.value || '').slice(0, 500));

        fetch('/my/speaking/transcribe', {
            method: 'POST',
            body: fd,
            credentials: 'include',
        })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            recordBtn.disabled = false;
            if (data.status === 'ok') {
                transEl.value = data.transcript || '';
                currentSessionId = data.session_id;
                analyzeBtn.disabled = !data.transcript;
                setStatus(
                    'Transcript ready (' + (data.duration || 0).toFixed(1) +
                    ' s, ' + (data.language || '?').toUpperCase() + '). Press Analyze.',
                    'ok',
                );
            } else {
                setStatus('Transcription failed: ' +
                          (data.message || 'unknown error'), 'error');
            }
        })
        .catch(function (err) {
            recordBtn.disabled = false;
            setStatus('Upload failed: ' + err, 'error');
        });
    }

    // ── Analyze ────────────────────────────────────────
    analyzeBtn.addEventListener('click', function () {
        if (!currentSessionId) { return; }
        analyzeBtn.disabled = true;
        setStatus('Analyzing speech with AI… (this may take 20-40 s)', 'busy');

        fetch('/my/speaking/analyze', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            credentials: 'include',
            body: JSON.stringify({jsonrpc: '2.0', method: 'call',
                                  params: {session_id: currentSessionId}}),
        })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            var result = (data && data.result) || {};
            if (result.status !== 'ok') {
                setStatus('Analysis failed: ' +
                          (result.message || 'unknown error'), 'error');
                analyzeBtn.disabled = false;
                return;
            }
            renderFeedback(result);
            setStatus('Analysis complete. Saved to your sessions.', 'ok');
        })
        .catch(function (err) {
            analyzeBtn.disabled = false;
            setStatus('Analyze request failed: ' + err, 'error');
        });
    });

    function renderFeedback(result) {
        fbPanel.classList.remove('d-none');

        var corrections = result.corrections || [];
        var synonyms    = result.synonyms || [];
        var improved    = result.improved || '';

        // Improved version
        if (improved && improved.trim()) {
            fbImproved.textContent = improved;
            fbImpBlock.classList.remove('d-none');
        } else {
            fbImpBlock.classList.add('d-none');
        }

        // Corrections
        fbCorrUl.innerHTML = '';
        if (corrections.length) {
            corrections.forEach(function (c) {
                var li = document.createElement('li');
                li.className = 'mb-2';
                li.innerHTML =
                    '<strong class="text-warning">' + escapeHtml(c.wrong || '') + '</strong> → ' +
                    '<strong class="text-success">' + escapeHtml(c.correct || '') + '</strong>' +
                    (c.note ? '<div class="small text-white-50">' + escapeHtml(c.note) + '</div>' : '');
                fbCorrUl.appendChild(li);
            });
            fbCorrBlk.classList.remove('d-none');
        } else {
            fbCorrBlk.classList.add('d-none');
        }

        // Synonyms
        fbSynUl.innerHTML = '';
        if (synonyms.length) {
            synonyms.forEach(function (s) {
                var li = document.createElement('li');
                li.className = 'mb-2';
                li.innerHTML =
                    '<span class="text-white-50">' + escapeHtml(s.original || '') + '</span> → ' +
                    '<strong class="text-info">' + escapeHtml(s.suggestion || '') + '</strong>' +
                    (s.reason ? '<div class="small text-white-50">' + escapeHtml(s.reason) + '</div>' : '');
                fbSynUl.appendChild(li);
            });
            fbSynBlk.classList.remove('d-none');
        } else {
            fbSynBlk.classList.add('d-none');
        }

        // Empty-state hint when nothing to show
        var anything = (improved && improved.trim()) ||
                       corrections.length ||
                       synonyms.length;
        if (!anything) {
            fbEmpty.classList.remove('d-none');
        } else {
            fbEmpty.classList.add('d-none');
        }
    }
})();
